const { execSync } = require('child_process');
const fs = require('fs');
try {
  execSync('npm run build', { encoding: 'utf8', stdio: 'pipe' });
  fs.writeFileSync('build_result.txt', 'Build succeeded');
} catch (e) {
  fs.writeFileSync('build_result.txt', e.stdout + '\n' + e.stderr);
}

import Sidebar from './Sidebar';
import Player from './Player';
import { Outlet, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';

export default function Layout() {
  const location = useLocation();

  return (
    <div className="flex h-screen overflow-hidden" style={{ background: '#0a0a0f' }}>
      <Sidebar />
      <main
        className="flex-1 overflow-y-auto pb-24"
        style={{ marginLeft: 240 }}
        id="main-content"
      >
        <AnimatePresence mode="wait">
          <motion.div
            key={location.pathname}
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -8 }}
            transition={{ duration: 0.2 }}
            className="min-h-full"
          >
            <Outlet />
          </motion.div>
        </AnimatePresence>
      </main>
      <Player />
    </div>
  );
}

import { usePlayer } from '../../context/PlayerContext';
import { useRef, useEffect, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import {
  HiPlay, HiPause, HiForward, HiBackward,
  HiSwitchHorizontal, HiRefresh, HiVolumeUp, HiVolumeOff,
  HiHeart
} from 'react-icons/hi';

function WaveformVisualizer({ isPlaying }) {
  const bars = 28;
  return (
    <div className="flex items-center gap-[2px] h-8">
      {Array.from({ length: bars }).map((_, i) => (
        <motion.div
          key={i}
          className="w-[3px] rounded-full"
          animate={isPlaying ? {
            scaleY: [0.2, 1, 0.3, 0.8, 0.2],
            transition: {
              duration: 1 + (i % 5) * 0.15,
              repeat: Infinity,
              delay: (i * 0.08) % 0.8,
              ease: 'easeInOut',
            }
          } : { scaleY: 0.2 }}
          style={{ originY: 1, background: 'linear-gradient(to top, #a855f7, #ec4899)' }}
        />
      ))}
    </div>
  );
}

function formatTime(s) {
  if (!s || isNaN(s)) return '0:00';
  const m = Math.floor(s / 60);
  const sec = Math.floor(s % 60);
  return `${m}:${sec.toString().padStart(2, '0')}`;
}

export default function Player() {
  const {
    currentSong, isPlaying, progress, duration, volume,
    shuffle, repeat, isLoading,
    togglePlay, playNext, playPrev, seek, changeVolume,
    toggleShuffle, toggleRepeat,
  } = usePlayer();

  const progressPercent = duration > 0 ? (progress / duration) * 100 : 0;

  const repeatIcon = {
    none: <HiRefresh className="text-xl" />,
    all: <span className="relative"><HiRefresh className="text-xl text-purple-400" /></span>,
    one: <span className="relative text-sm font-bold text-purple-400">1↺</span>,
  };

  if (!currentSong) {
    return (
      <div
        className="fixed bottom-0 left-0 right-0 h-20 z-50"
        style={{ background: 'rgba(10,10,20,0.95)', borderTop: '1px solid rgba(168,85,247,0.1)' }}
      >
        <div className="flex items-center justify-center h-full">
          <p className="text-gray-600 text-sm">No song playing</p>
        </div>
      </div>
    );
  }

  return (
    <motion.div
      initial={{ y: 100 }}
      animate={{ y: 0 }}
      className="fixed bottom-0 left-0 right-0 z-50 px-4"
      style={{
        background: 'rgba(8, 8, 16, 0.97)',
        backdropFilter: 'blur(20px)',
        borderTop: '1px solid rgba(168,85,247,0.15)',
      }}
    >
      {/* Progress bar on top */}
      <div className="absolute top-0 left-0 right-0 h-0.5" style={{ background: 'rgba(255,255,255,0.05)' }}>
        <div
          className="h-full transition-all duration-100"
          style={{
            width: `${progressPercent}%`,
            background: 'linear-gradient(to right, #a855f7, #ec4899)',
          }}
        />
      </div>

      <div className="flex items-center gap-4 h-20 max-w-screen-xl mx-auto">
        {/* Song info */}
        <div className="flex items-center gap-3 w-56 flex-shrink-0">
          <div className="relative flex-shrink-0">
            <motion.img
              src={currentSong.coverImage}
              alt={currentSong.title}
              className="w-12 h-12 rounded-lg object-cover shadow-lg"
              animate={isPlaying ? { rotate: [0, 360] } : {}}
              transition={isPlaying ? { duration: 8, repeat: Infinity, ease: 'linear' } : {}}
            />
            {isPlaying && (
              <div className="absolute -bottom-1 -right-1 w-4 h-4 gradient-bg rounded-full flex items-center justify-center">
                <div className="w-1.5 h-1.5 bg-white rounded-full animate-pulse" />
              </div>
            )}
          </div>
          <div className="min-w-0">
            <Link
              to={`/song/${currentSong._id}`}
              className="text-sm font-medium text-white hover:text-purple-400 transition-colors truncate block"
            >
              {currentSong.title}
            </Link>
            <Link
              to={`/artist/${currentSong.artist?._id}`}
              className="text-xs text-gray-500 hover:text-purple-400 transition-colors truncate block"
            >
              {currentSong.artist?.name || 'Unknown Artist'}
            </Link>
          </div>
        </div>

        {/* Waveform + Controls */}
        <div className="flex-1 flex flex-col items-center gap-1">
          <div className="hidden md:block mb-1">
            <WaveformVisualizer isPlaying={isPlaying} />
          </div>

          {/* Buttons */}
          <div className="flex items-center gap-4">
            <button
              onClick={toggleShuffle}
              className={`transition-colors ${shuffle ? 'text-purple-400' : 'text-gray-500 hover:text-white'}`}
              title="Shuffle (Shift+←)"
            >
              <HiSwitchHorizontal className="text-lg" />
            </button>

            <button
              onClick={playPrev}
              className="text-gray-400 hover:text-white transition-colors"
              title="Previous (Shift+←)"
            >
              <HiBackward className="text-xl" />
            </button>

            <button
              onClick={togglePlay}
              disabled={isLoading}
              className="w-10 h-10 rounded-full gradient-bg flex items-center justify-center hover:scale-110 transition-transform shadow-lg shadow-purple-500/30 disabled:opacity-60"
            >
              {isLoading
                ? <div className="w-4 h-4 border-2 border-white/50 border-t-white rounded-full animate-spin" />
                : isPlaying
                  ? <HiPause className="text-white text-xl" />
                  : <HiPlay className="text-white text-xl ml-0.5" />}
            </button>

            <button
              onClick={playNext}
              className="text-gray-400 hover:text-white transition-colors"
              title="Next (Shift+→)"
            >
              <HiForward className="text-xl" />
            </button>

            <button
              onClick={toggleRepeat}
              className={`transition-colors ${repeat !== 'none' ? 'text-purple-400' : 'text-gray-500 hover:text-white'}`}
              title="Repeat"
            >
              {repeatIcon[repeat]}
            </button>
          </div>

          {/* Seek bar */}
          <div className="flex items-center gap-2 w-full max-w-lg">
            <span className="text-xs text-gray-600 w-8 text-right">{formatTime(progress)}</span>
            <input
              type="range"
              min={0}
              max={duration || 100}
              value={progress}
              onChange={(e) => seek(parseFloat(e.target.value))}
              className="flex-1 h-1 cursor-pointer"
              style={{
                background: `linear-gradient(to right, #a855f7 ${progressPercent}%, rgba(255,255,255,0.15) ${progressPercent}%)`
              }}
            />
            <span className="text-xs text-gray-600 w-8">{formatTime(duration)}</span>
          </div>
        </div>

        {/* Volume */}
        <div className="hidden md:flex items-center gap-2 w-36 flex-shrink-0 justify-end">
          <button
            onClick={() => changeVolume(volume > 0 ? 0 : 0.8)}
            className="text-gray-500 hover:text-white transition-colors"
          >
            {volume === 0 ? <HiVolumeOff className="text-lg" /> : <HiVolumeUp className="text-lg" />}
          </button>
          <input
            type="range"
            min={0}
            max={1}
            step={0.02}
            value={volume}
            onChange={(e) => changeVolume(parseFloat(e.target.value))}
            className="w-20 h-1 cursor-pointer"
            style={{
              background: `linear-gradient(to right, #a855f7 ${volume * 100}%, rgba(255,255,255,0.15) ${volume * 100}%)`
            }}
          />
        </div>
      </div>
    </motion.div>
  );
}

import { NavLink, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { useAuth } from '../../context/AuthContext';
import { usePlayer } from '../../context/PlayerContext';
import { playlistsAPI } from '../../services/api';
import { useState, useEffect } from 'react';
import {
  HiHome, HiSearch, HiCollection, HiHeart, HiPlus,
  HiMusicalNote, HiLogout, HiUpload
} from 'react-icons/hi';

const navItems = [
  { to: '/', icon: HiHome, label: 'Home' },
  { to: '/search', icon: HiSearch, label: 'Search' },
  { to: '/library', icon: HiCollection, label: 'Your Library' },
];

export default function Sidebar() {
  const { user, logout } = useAuth();
  const { currentSong } = usePlayer();
  const navigate = useNavigate();
  const [playlists, setPlaylists] = useState([]);
  const [collapsed, setCollapsed] = useState(false);

  useEffect(() => {
    if (user) {
      playlistsAPI.getAll()
        .then(({ data }) => setPlaylists(data.playlists || []))
        .catch(() => {});
    }
  }, [user]);

  const handleLogout = () => { logout(); navigate('/login'); };

  return (
    <motion.div
      animate={{ width: collapsed ? 72 : 240 }}
      transition={{ duration: 0.2 }}
      className="hidden md:flex flex-col fixed left-0 top-0 h-full z-40 overflow-hidden"
      style={{
        background: 'rgba(10, 10, 20, 0.95)',
        borderRight: '1px solid rgba(168, 85, 247, 0.1)',
      }}
    >
      {/* Logo */}
      <div className="flex items-center gap-3 px-4 py-5 border-b border-purple-500/10">
        <button
          onClick={() => setCollapsed(!collapsed)}
          className="w-9 h-9 rounded-xl gradient-bg flex items-center justify-center flex-shrink-0 shadow-lg hover:scale-105 transition-transform"
        >
          <HiMusicalNote className="text-white text-lg" />
        </button>
        <AnimatePresence>
          {!collapsed && (
            <motion.span
              initial={{ opacity: 0, x: -10 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -10 }}
              className="font-bold text-xl gradient-text select-none"
            >
              Musify
            </motion.span>
          )}
        </AnimatePresence>
      </div>

      {/* Nav items */}
      <nav className="flex-1 p-3 overflow-y-auto">
        <div className="space-y-1">
          {navItems.map(({ to, icon: Icon, label }) => (
            <NavLink
              key={to}
              to={to}
              end={to === '/'}
              className={({ isActive }) =>
                `flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 group
                ${isActive
                  ? 'gradient-bg text-white shadow-lg shadow-purple-500/20'
                  : 'text-gray-400 hover:text-white hover:bg-white/5'}`
              }
            >
              <Icon className={`text-xl flex-shrink-0 ${!collapsed ? '' : 'mx-auto'}`} />
              {!collapsed && <span className="text-sm font-medium">{label}</span>}
            </NavLink>
          ))}

          <NavLink
            to="/liked"
            className={({ isActive }) =>
              `flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200
              ${isActive ? 'gradient-bg text-white shadow-lg' : 'text-gray-400 hover:text-white hover:bg-white/5'}`
            }
          >
            <HiHeart className={`text-xl flex-shrink-0 ${!collapsed ? '' : 'mx-auto'}`} />
            {!collapsed && <span className="text-sm font-medium">Liked Songs</span>}
          </NavLink>

          {user?.role === 'admin' && (
            <NavLink
              to="/upload"
              className={({ isActive }) =>
                `flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200
                ${isActive ? 'gradient-bg text-white' : 'text-gray-400 hover:text-white hover:bg-white/5'}`
              }
            >
              <HiUpload className={`text-xl flex-shrink-0 ${!collapsed ? '' : 'mx-auto'}`} />
              {!collapsed && <span className="text-sm font-medium">Upload</span>}
            </NavLink>
          )}
        </div>

        {/* Playlists section */}
        {!collapsed && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="mt-6"
          >
            <div className="flex items-center justify-between px-3 mb-2">
              <span className="text-xs font-semibold text-gray-500 uppercase tracking-widest">Playlists</span>
              <button
                onClick={() => navigate('/library')}
                className="text-gray-500 hover:text-purple-400 transition-colors p-1 rounded-lg hover:bg-white/5"
              >
                <HiPlus />
              </button>
            </div>
            <div className="space-y-0.5">
              {playlists.map((pl) => (
                <NavLink
                  key={pl._id}
                  to={`/playlist/${pl._id}`}
                  className={({ isActive }) =>
                    `flex items-center gap-2.5 px-3 py-2 rounded-lg text-sm transition-colors
                    ${isActive ? 'text-purple-400 bg-purple-500/10' : 'text-gray-500 hover:text-gray-300 hover:bg-white/5'}`
                  }
                >
                  {pl.coverImage
                    ? <img src={pl.coverImage} alt={pl.name} className="w-8 h-8 rounded object-cover flex-shrink-0" />
                    : <div className="w-8 h-8 rounded gradient-bg flex items-center justify-center flex-shrink-0">
                        <HiMusicalNote className="text-white text-xs" />
                      </div>}
                  <span className="truncate">{pl.name}</span>
                </NavLink>
              ))}
            </div>
          </motion.div>
        )}
      </nav>

      {/* User section */}
      {user && (
        <div className={`p-3 border-t border-purple-500/10 ${collapsed ? '' : ''}`}>
          <div className="flex items-center gap-2 px-2 py-2 rounded-xl hover:bg-white/5 transition-colors group">
            <img
              src={user.avatar}
              alt={user.username}
              className="w-8 h-8 rounded-full object-cover border border-purple-500/30 flex-shrink-0"
              onError={(e) => { e.target.src = `https://ui-avatars.com/api/?name=${user.username}&background=a855f7&color=fff`; }}
            />
            {!collapsed && (
              <>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-white truncate">{user.username}</p>
                  <p className="text-xs text-gray-500 truncate">{user.role}</p>
                </div>
                <button
                  onClick={handleLogout}
                  className="text-gray-500 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100 p-1"
                  title="Logout"
                >
                  <HiLogout />
                </button>
              </>
            )}
          </div>
        </div>
      )}
    </motion.div>
  );
}

import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import { HiBadgeCheck } from 'react-icons/hi';

export function ArtistCard({ artist }) {
  return (
    <Link to={`/artist/${artist._id}`}>
      <motion.div
        whileHover={{ scale: 1.05 }}
        className="flex flex-col items-center p-4 rounded-2xl cursor-pointer group card-hover text-center"
        style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.06)' }}
      >
        <div className="relative mb-3">
          <img
            src={artist.image || `https://ui-avatars.com/api/?name=${encodeURIComponent(artist.name)}&background=a855f7&color=fff&size=200`}
            alt={artist.name}
            className="w-24 h-24 rounded-full object-cover border-2 border-purple-500/20 group-hover:border-purple-500/60 transition-all shadow-xl"
            loading="lazy"
          />
          {artist.verified && (
            <div className="absolute -bottom-1 -right-1 w-6 h-6 gradient-bg rounded-full flex items-center justify-center">
              <HiBadgeCheck className="text-white text-xs" />
            </div>
          )}
        </div>
        <p className="text-sm font-bold text-white truncate max-w-full">{artist.name}</p>
        <p className="text-xs text-gray-500 mt-0.5">{artist.genre || 'Artist'}</p>
        {artist.followers?.length > 0 && (
          <p className="text-xs text-gray-600 mt-1">
            {artist.followers.length.toLocaleString()} followers
          </p>
        )}
      </motion.div>
    </Link>
  );
}

import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import { HiMusicalNote, HiPlay } from 'react-icons/hi';

export function PlaylistCard({ playlist }) {
  return (
    <Link to={`/playlist/${playlist._id}`}>
      <motion.div
        whileHover={{ scale: 1.03 }}
        className="group rounded-2xl overflow-hidden cursor-pointer card-hover"
        style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.06)' }}
      >
        <div className="relative aspect-square">
          {playlist.coverImage ? (
            <img
              src={playlist.coverImage}
              alt={playlist.name}
              className="w-full h-full object-cover"
              loading="lazy"
            />
          ) : (
            <div className="w-full h-full flex items-center justify-center gradient-bg-subtle">
              <HiMusicalNote className="text-4xl text-purple-400/60" />
            </div>
          )}
          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-all duration-300 flex items-center justify-center">
            <div className="w-12 h-12 rounded-full gradient-bg flex items-center justify-center shadow-2xl transform scale-0 group-hover:scale-100 transition-transform duration-300">
              <HiPlay className="text-white text-xl ml-0.5" />
            </div>
          </div>
        </div>
        <div className="p-3">
          <p className="text-sm font-bold text-white truncate">{playlist.name}</p>
          <p className="text-xs text-gray-500 mt-0.5">
            {playlist.songs?.length || 0} songs
            {playlist.owner && ` · ${playlist.owner.username || playlist.owner}`}
          </p>
        </div>
      </motion.div>
    </Link>
  );
}

import { motion } from 'framer-motion';
import { usePlayer } from '../../context/PlayerContext';
import { useAuth } from '../../context/AuthContext';
import { songsAPI } from '../../services/api';
import { Link } from 'react-router-dom';
import { useState } from 'react';
import { HiPlay, HiPause, HiHeart, HiDotsVertical } from 'react-icons/hi';

function formatTime(s) {
  if (!s || isNaN(s)) return '0:00';
  return `${Math.floor(s / 60)}:${Math.floor(s % 60).toString().padStart(2, '0')}`;
}

export function SongCard({ song, queue = [], queueIndex = 0, onLikeToggle }) {
  const { playSong, currentSong, isPlaying } = usePlayer();
  const { user } = useAuth();
  const isCurrentSong = currentSong?._id === song._id;
  const [liked, setLiked] = useState(user?.likedSongs?.includes(song._id));

  const handleLike = async (e) => {
    e.preventDefault();
    if (!user) return;
    try {
      await songsAPI.like(song._id);
      setLiked(!liked);
      onLikeToggle?.(song._id);
    } catch {}
  };

  return (
    <motion.div
      whileHover={{ scale: 1.02 }}
      className="group relative rounded-2xl overflow-hidden cursor-pointer card-hover"
      style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.06)' }}
      onClick={() => playSong(song, queue, queueIndex)}
    >
      <div className="relative">
        <img
          src={song.coverImage}
          alt={song.title}
          className="w-full aspect-square object-cover"
          loading="lazy"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent opacity-0 group-hover:opacity-100 transition-all duration-300" />
        <motion.button
          initial={{ scale: 0 }}
          whileHover={{ scale: 1.1 }}
          className="absolute bottom-3 right-3 w-11 h-11 rounded-full gradient-bg flex items-center justify-center shadow-2xl opacity-0 group-hover:opacity-100 transition-all duration-300"
          onClick={(e) => { e.stopPropagation(); playSong(song, queue, queueIndex); }}
        >
          {isCurrentSong && isPlaying
            ? <HiPause className="text-white text-xl" />
            : <HiPlay className="text-white text-xl ml-0.5" />}
        </motion.button>
        {isCurrentSong && isPlaying && (
          <div className="absolute top-2 right-2 flex gap-0.5 items-end h-4">
            {[1, 2, 3].map((i) => (
              <motion.div
                key={i}
                className="w-0.5 rounded-full"
                style={{ background: 'linear-gradient(to top, #a855f7, #ec4899)' }}
                animate={{ scaleY: [0.3, 1, 0.3], transition: { duration: 0.8, delay: i * 0.1, repeat: Infinity } }}
              />
            ))}
          </div>
        )}
      </div>
      <div className="p-3">
        <div className="flex items-center justify-between">
          <div className="min-w-0 flex-1">
            <p className={`text-sm font-medium truncate ${isCurrentSong ? 'gradient-text' : 'text-white'}`}>
              {song.title}
            </p>
            <Link
              to={`/artist/${song.artist?._id}`}
              className="text-xs text-gray-500 hover:text-purple-400 transition-colors truncate block"
              onClick={(e) => e.stopPropagation()}
            >
              {song.artist?.name || 'Unknown'}
            </Link>
          </div>
          <div className="flex items-center gap-1 ml-2">
            <button
              onClick={handleLike}
              className={`p-1.5 rounded-full transition-colors opacity-0 group-hover:opacity-100 ${liked ? 'text-pink-500' : 'text-gray-600 hover:text-pink-400'}`}
            >
              <HiHeart className={liked ? 'fill-current' : ''} />
            </button>
            <span className="text-xs text-gray-600">{formatTime(song.duration)}</span>
          </div>
        </div>
      </div>
    </motion.div>
  );
}

export function SongRow({ song, index, queue = [], showIndex = true, onLikeToggle, onRemove }) {
  const { playSong, currentSong, isPlaying } = usePlayer();
  const { user } = useAuth();
  const isCurrentSong = currentSong?._id === song._id;
  const [liked, setLiked] = useState(user?.likedSongs?.includes(song._id));

  const handleLike = async (e) => {
    e.stopPropagation();
    if (!user) return;
    await songsAPI.like(song._id);
    setLiked(!liked);
    onLikeToggle?.(song._id);
  };

  return (
    <motion.div
      whileHover={{ backgroundColor: 'rgba(255,255,255,0.05)' }}
      className={`flex items-center gap-4 px-4 py-2.5 rounded-xl cursor-pointer group transition-all ${isCurrentSong ? 'bg-purple-500/10' : ''}`}
      onClick={() => playSong(song, queue, index)}
    >
      <div className="w-8 text-center flex-shrink-0">
        {isCurrentSong && isPlaying
          ? <div className="flex gap-0.5 items-end h-4 justify-center">
              {[1,2,3].map(i => (
                <motion.div key={i} className="w-0.5 rounded-full"
                  style={{ background: 'linear-gradient(to top, #a855f7, #ec4899)' }}
                  animate={{ scaleY: [0.3, 1, 0.3] }}
                  transition={{ duration: 0.8, delay: i*0.1, repeat: Infinity }} />
              ))}
            </div>
          : showIndex
            ? <span className="text-sm text-gray-500 group-hover:hidden">{index + 1}</span>
            : null}
        <HiPlay className={`text-white mx-auto hidden group-hover:block ${isCurrentSong && isPlaying ? '!hidden' : ''}`} />
      </div>
      <img src={song.coverImage} alt={song.title} className="w-10 h-10 rounded object-cover flex-shrink-0" loading="lazy" />
      <div className="flex-1 min-w-0">
        <p className={`text-sm font-medium truncate ${isCurrentSong ? 'gradient-text' : 'text-white'}`}>{song.title}</p>
        <Link to={`/artist/${song.artist?._id}`} onClick={e => e.stopPropagation()}
          className="text-xs text-gray-500 hover:text-purple-400 transition-colors truncate block">
          {song.artist?.name || 'Unknown'}
        </Link>
      </div>
      <span className="text-xs text-gray-600 hidden sm:block">{song.album || 'Single'}</span>
      <div className="flex items-center gap-1">
        <button onClick={handleLike}
          className={`p-1.5 transition-colors opacity-0 group-hover:opacity-100 ${liked ? 'text-pink-500 opacity-100' : 'text-gray-600 hover:text-pink-400'}`}>
          <HiHeart className={liked ? 'fill-current' : ''} />
        </button>
        <span className="text-xs text-gray-600 w-10 text-right">{formatTime(song.duration)}</span>
        {onRemove && (
          <button onClick={(e) => { e.stopPropagation(); onRemove(song._id); }}
            className="p-1.5 text-gray-600 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100">
            ✕
          </button>
        )}
      </div>
    </motion.div>
  );
}

import { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { authAPI } from '../services/api';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const loadUser = useCallback(async () => {
    const token = localStorage.getItem('musify_token');
    if (!token) { setLoading(false); return; }
    try {
      const { data } = await authAPI.getProfile();
      setUser(data.user);
    } catch {
      localStorage.removeItem('musify_token');
      localStorage.removeItem('musify_user');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadUser();
    const handleLogout = () => { setUser(null); setLoading(false); };
    window.addEventListener('auth:logout', handleLogout);
    return () => window.removeEventListener('auth:logout', handleLogout);
  }, [loadUser]);

  const register = async (username, email, password) => {
    setError(null);
    const { data } = await authAPI.register({ username, email, password });
    localStorage.setItem('musify_token', data.token);
    setUser(data.user);
    return data;
  };

  const login = async (email, password) => {
    setError(null);
    const { data } = await authAPI.login({ email, password });
    localStorage.setItem('musify_token', data.token);
    setUser(data.user);
    return data;
  };

  const logout = () => {
    localStorage.removeItem('musify_token');
    localStorage.removeItem('musify_user');
    setUser(null);
  };

  const updateUser = (updatedUser) => setUser(updatedUser);

  return (
    <AuthContext.Provider value={{ user, loading, error, register, login, logout, updateUser }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
};

export default AuthContext;

import { createContext, useContext, useState, useRef, useEffect, useCallback } from 'react';
import { songsAPI } from '../services/api';

const PlayerContext = createContext(null);

export const PlayerProvider = ({ children }) => {
  const [currentSong, setCurrentSong] = useState(null);
  const [queue, setQueue] = useState([]);
  const [queueIndex, setQueueIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(
    () => parseFloat(localStorage.getItem('musify_volume') || '0.8')
  );
  const [shuffle, setShuffle] = useState(false);
  const [repeat, setRepeat] = useState('none'); // 'none' | 'all' | 'one'
  const [isLoading, setIsLoading] = useState(false);
  const audioRef = useRef(new Audio());

  // Restore progress from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('musify_progress');
    if (saved) {
      try {
        const { songId, time } = JSON.parse(saved);
        if (currentSong?._id === songId) {
          audioRef.current.currentTime = time;
        }
      } catch {}
    }
  }, [currentSong]);

  useEffect(() => {
    const audio = audioRef.current;
    audio.volume = volume;

    const handleTimeUpdate = () => {
      setProgress(audio.currentTime);
      if (currentSong) {
        localStorage.setItem('musify_progress', JSON.stringify({
          songId: currentSong._id,
          time: audio.currentTime,
        }));
      }
    };
    const handleDuration = () => setDuration(audio.duration || 0);
    const handleEnded = () => handleSongEnd();
    const handleLoadStart = () => setIsLoading(true);
    const handleCanPlay = () => setIsLoading(false);

    audio.addEventListener('timeupdate', handleTimeUpdate);
    audio.addEventListener('durationchange', handleDuration);
    audio.addEventListener('ended', handleEnded);
    audio.addEventListener('loadstart', handleLoadStart);
    audio.addEventListener('canplay', handleCanPlay);

    return () => {
      audio.removeEventListener('timeupdate', handleTimeUpdate);
      audio.removeEventListener('durationchange', handleDuration);
      audio.removeEventListener('ended', handleEnded);
      audio.removeEventListener('loadstart', handleLoadStart);
      audio.removeEventListener('canplay', handleCanPlay);
    };
  });

  const handleSongEnd = () => {
    if (repeat === 'one') {
      audioRef.current.currentTime = 0;
      audioRef.current.play();
    } else if (repeat === 'all' || queueIndex < queue.length - 1) {
      playNext();
    } else {
      setIsPlaying(false);
    }
  };

  const playSong = useCallback(async (song, newQueue = null, index = 0) => {
    if (newQueue) {
      setQueue(newQueue);
      setQueueIndex(index);
    }
    if (currentSong?._id === song._id) {
      if (isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
      } else {
        audioRef.current.play();
        setIsPlaying(true);
      }
      return;
    }

    setCurrentSong(song);
    setIsLoading(true);
    audioRef.current.src = song.audioUrl;
    audioRef.current.load();

    try {
      await audioRef.current.play();
      setIsPlaying(true);
      songsAPI.recordPlay(song._id).catch(() => {});
    } catch (e) {
      setIsPlaying(false);
    } finally {
      setIsLoading(false);
    }
  }, [currentSong, isPlaying]);

  const togglePlay = () => {
    if (!currentSong) return;
    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      audioRef.current.play();
      setIsPlaying(true);
    }
  };

  const playNext = useCallback(() => {
    if (!queue.length) return;
    let nextIndex;
    if (shuffle) {
      nextIndex = Math.floor(Math.random() * queue.length);
    } else {
      nextIndex = (queueIndex + 1) % queue.length;
    }
    setQueueIndex(nextIndex);
    playSong(queue[nextIndex]);
  }, [queue, queueIndex, shuffle, playSong]);

  const playPrev = useCallback(() => {
    if (!queue.length) return;
    if (audioRef.current.currentTime > 3) {
      audioRef.current.currentTime = 0;
      return;
    }
    const prevIndex = queueIndex === 0 ? queue.length - 1 : queueIndex - 1;
    setQueueIndex(prevIndex);
    playSong(queue[prevIndex]);
  }, [queue, queueIndex, playSong]);

  const seek = (time) => {
    audioRef.current.currentTime = time;
    setProgress(time);
  };

  const changeVolume = (val) => {
    audioRef.current.volume = val;
    setVolume(val);
    localStorage.setItem('musify_volume', val.toString());
  };

  const toggleShuffle = () => setShuffle((s) => !s);
  const toggleRepeat = () => {
    setRepeat((r) => {
      if (r === 'none') return 'all';
      if (r === 'all') return 'one';
      return 'none';
    });
  };

  const addToQueue = (song) => setQueue((q) => [...q, song]);

  // Keyboard shortcuts
  useEffect(() => {
    const handleKey = (e) => {
      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') return;
      if (e.code === 'Space') { e.preventDefault(); togglePlay(); }
      if (e.code === 'ArrowRight' && e.shiftKey) playNext();
      if (e.code === 'ArrowLeft' && e.shiftKey) playPrev();
      if (e.code === 'KeyM') changeVolume(volume > 0 ? 0 : 0.8);
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [isPlaying, volume, playNext, playPrev]);

  return (
    <PlayerContext.Provider value={{
      currentSong, queue, isPlaying, progress, duration, volume,
      shuffle, repeat, isLoading, audioRef,
      playSong, togglePlay, playNext, playPrev, seek, changeVolume,
      toggleShuffle, toggleRepeat, addToQueue, setQueue, setQueueIndex
    }}>
      {children}
    </PlayerContext.Provider>
  );
};

export const usePlayer = () => {
  const ctx = useContext(PlayerContext);
  if (!ctx) throw new Error('usePlayer must be used within PlayerProvider');
  return ctx;
};

export default PlayerContext;

import { createContext, useContext, useState, useEffect } from 'react';

const ThemeContext = createContext(null);

export const ThemeProvider = ({ children }) => {
  const [theme, setTheme] = useState(
    () => localStorage.getItem('musify_theme') || 'dark'
  );

  useEffect(() => {
    document.documentElement.classList.toggle('light', theme === 'light');
    localStorage.setItem('musify_theme', theme);
  }, [theme]);

  const toggleTheme = () => setTheme((t) => (t === 'dark' ? 'light' : 'dark'));

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => useContext(ThemeContext);
export default ThemeContext;

import { createContext, useContext, useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const ToastContext = createContext(null);

const Toast = ({ toast }) => {
  const icons = { success: '✓', error: '✕', info: 'ℹ', warning: '⚠' };
  const colors = {
    success: 'border-green-500/50 bg-green-500/10',
    error: 'border-red-500/50 bg-red-500/10',
    info: 'border-purple-500/50 bg-purple-500/10',
    warning: 'border-yellow-500/50 bg-yellow-500/10',
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 50, scale: 0.95 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      exit={{ opacity: 0, y: 20, scale: 0.95 }}
      className={`glass border rounded-xl px-4 py-3 flex items-center gap-3 min-w-64 max-w-sm shadow-2xl ${colors[toast.type] || colors.info}`}
    >
      <span className="text-lg">{icons[toast.type]}</span>
      <p className="text-sm text-white">{toast.message}</p>
    </motion.div>
  );
};

export const ToastProvider = ({ children }) => {
  const [toasts, setToasts] = useState([]);

  const addToast = useCallback((message, type = 'info', duration = 3000) => {
    const id = Date.now();
    setToasts((t) => [...t, { id, message, type }]);
    setTimeout(() => setToasts((t) => t.filter((x) => x.id !== id)), duration);
  }, []);

  const toast = {
    success: (msg) => addToast(msg, 'success'),
    error: (msg) => addToast(msg, 'error'),
    info: (msg) => addToast(msg, 'info'),
    warning: (msg) => addToast(msg, 'warning'),
  };

  return (
    <ToastContext.Provider value={{ toast }}>
      {children}
      <div className="fixed bottom-28 right-4 z-[9999] flex flex-col gap-2">
        <AnimatePresence>
          {toasts.map((t) => <Toast key={t.id} toast={t} />)}
        </AnimatePresence>
      </div>
    </ToastContext.Provider>
  );
};

export const useToast = () => useContext(ToastContext);
export default ToastContext;

import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { motion } from 'framer-motion';
import { artistsAPI } from '../services/api';
import { SongRow } from '../components/ui/SongCard';
import { SkeletonBanner, SkeletonRow } from '../components/ui/Skeleton';
import { usePlayer } from '../context/PlayerContext';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { HiBadgeCheck, HiPlay, HiUserAdd, HiUserRemove } from 'react-icons/hi';

export default function ArtistPage() {
  const { id } = useParams();
  const [artist, setArtist] = useState(null);
  const [loading, setLoading] = useState(true);
  const [following, setFollowing] = useState(false);
  const { playSong } = usePlayer();
  const { user } = useAuth();
  const { toast } = useToast();

  useEffect(() => {
    artistsAPI.getById(id)
      .then(({ data }) => {
        setArtist(data.artist);
        setFollowing(data.artist.followers?.includes(user?._id));
      })
      .catch(() => toast.error('Failed to load artist'))
      .finally(() => setLoading(false));
  }, [id]);

  const handleFollow = async () => {
    if (!user) { toast.info('Login to follow artists'); return; }
    try {
      await artistsAPI.follow(id);
      setFollowing(!following);
      toast.success(following ? 'Unfollowed artist' : 'Following artist! 🎤');
    } catch { toast.error('Failed to update follow'); }
  };

  if (loading) return (
    <div className="p-0">
      <SkeletonBanner />
      <div className="p-6 space-y-4">{Array.from({length:5}).map((_,i) => <SkeletonRow key={i} />)}</div>
    </div>
  );

  if (!artist) return (
    <div className="p-8 text-center py-20">
      <p className="text-gray-400">Artist not found</p>
    </div>
  );

  return (
    <div>
      {/* Banner */}
      <div className="relative h-64 md:h-80 overflow-hidden">
        {artist.banner
          ? <img src={artist.banner} alt="" className="w-full h-full object-cover" />
          : <div className="w-full h-full"
              style={{ background: 'linear-gradient(135deg, #a855f720, #ec489910, #0a0a0f)' }} />}
        <div className="absolute inset-0 bg-gradient-to-t from-[#0a0a0f] via-[#0a0a0f]/50 to-transparent" />

        {/* Artist info overlay */}
        <div className="absolute bottom-0 left-0 p-6 md:p-10 flex items-end gap-5">
          <img
            src={artist.image || `https://ui-avatars.com/api/?name=${encodeURIComponent(artist.name)}&background=a855f7&color=fff&size=200`}
            alt={artist.name}
            className="w-24 h-24 md:w-32 md:h-32 rounded-full object-cover border-4 border-purple-500/30 shadow-2xl flex-shrink-0"
          />
          <div>
            <div className="flex items-center gap-2 mb-1">
              {artist.verified && <HiBadgeCheck className="text-purple-400 text-xl" />}
              <span className="text-xs text-gray-400 uppercase tracking-widest">Artist</span>
            </div>
            <h1 className="text-4xl md:text-6xl font-black text-white">{artist.name}</h1>
            <p className="text-gray-400 text-sm mt-1">
              {(artist.followers?.length || 0).toLocaleString()} followers
              {artist.genre && ` · ${artist.genre}`}
            </p>
          </div>
        </div>
      </div>

      {/* Controls */}
      <div className="px-6 md:px-10 py-6 flex items-center gap-4">
        {artist.songs?.length > 0 && (
          <motion.button
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            onClick={() => playSong(artist.songs[0], artist.songs, 0)}
            className="w-14 h-14 rounded-full gradient-bg flex items-center justify-center shadow-xl shadow-purple-500/30"
          >
            <HiPlay className="text-white text-2xl ml-0.5" />
          </motion.button>
        )}
        <motion.button
          whileHover={{ scale: 1.03 }}
          onClick={handleFollow}
          className={`flex items-center gap-2 px-5 py-2.5 rounded-full text-sm font-semibold transition-all border ${
            following
              ? 'border-purple-500/40 text-purple-400 bg-purple-500/10'
              : 'border-white/20 text-white glass hover:border-purple-500/40'}`}
        >
          {following ? <HiUserRemove /> : <HiUserAdd />}
          {following ? 'Following' : 'Follow'}
        </motion.button>
      </div>

      {/* Bio */}
      {artist.bio && (
        <div className="px-6 md:px-10 mb-8">
          <div className="glass rounded-2xl p-5">
            <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-3">About</h3>
            <p className="text-gray-300 text-sm leading-relaxed">{artist.bio}</p>
          </div>
        </div>
      )}

      {/* Popular songs */}
      {artist.songs?.length > 0 && (
        <div className="px-6 md:px-10 mb-8">
          <h2 className="text-xl font-bold text-white mb-4">Popular</h2>
          <div className="space-y-1">
            {artist.songs.map((song, i) => (
              <SongRow key={song._id} song={{ ...song, artist: { _id: artist._id, name: artist.name, image: artist.image } }}
                index={i} queue={artist.songs} />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

