import { useState, useEffect, useRef, useCallback } from 'react';
import { motion } from 'framer-motion';
import { songsAPI, artistsAPI, playlistsAPI } from '../services/api';
import { SongCard } from '../components/ui/SongCard';
import { ArtistCard } from '../components/ui/ArtistCard';
import { PlaylistCard } from '../components/ui/PlaylistCard';
import { SkeletonCard, SkeletonArtist } from '../components/ui/Skeleton';
import { useAuth } from '../context/AuthContext';
import { usePlayer } from '../context/PlayerContext';
import { HiPlay, HiSparkles } from 'react-icons/hi';

function Section({ title, children, loading, count = 5 }) {
  return (
    <div className="mb-10">
      <h2 className="text-xl font-bold text-white mb-4 flex items-center gap-2">{title}</h2>
      {loading
        ? <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
            {Array.from({ length: count }).map((_, i) => <SkeletonCard key={i} />)}
          </div>
        : children}
    </div>
  );
}

export default function Home() {
  const { user } = useAuth();
  const { playSong } = usePlayer();
  const [songs, setSongs] = useState([]);
  const [trending, setTrending] = useState([]);
  const [artists, setArtists] = useState([]);
  const [playlists, setPlaylists] = useState([]);
  const [recentlyPlayed, setRecentlyPlayed] = useState([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const observerRef = useRef(null);
  const bottomRef = useRef(null);

  useEffect(() => {
    (async () => {
      try {
        const [trendRes, artistRes, playlistRes] = await Promise.all([
          songsAPI.getTrending(),
          artistsAPI.getAll(),
          playlistsAPI.getPublic(),
        ]);
        setTrending(trendRes.data.songs || []);
        setArtists(artistRes.data.artists || []);
        setPlaylists(playlistRes.data.playlists || []);
        if (user?.recentlyPlayed) {
          setRecentlyPlayed(user.recentlyPlayed.slice(0, 10).map(r => r.song).filter(Boolean));
        }
      } catch {}
      setLoading(false);
    })();
  }, [user]);

  const loadMoreSongs = useCallback(async () => {
    if (!hasMore) return;
    try {
      const { data } = await songsAPI.getAll(page, 10);
      setSongs(prev => [...prev, ...(data.songs || [])]);
      setHasMore(data.pagination?.page < data.pagination?.pages);
      setPage(p => p + 1);
    } catch {}
  }, [page, hasMore]);

  useEffect(() => {
    loadMoreSongs();
  }, []);

  useEffect(() => {
    if (!bottomRef.current) return;
    const observer = new IntersectionObserver(
      entries => { if (entries[0].isIntersecting) loadMoreSongs(); },
      { threshold: 0.1 }
    );
    observer.observe(bottomRef.current);
    return () => observer.disconnect();
  }, [loadMoreSongs]);

  const greeting = () => {
    const h = new Date().getHours();
    if (h < 12) return 'Good morning';
    if (h < 18) return 'Good afternoon';
    return 'Good evening';
  };

  return (
    <div className="p-6 md:p-8">
      {/* Hero greeting */}
      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="mb-10"
      >
        <div className="relative rounded-3xl overflow-hidden p-8 md:p-12"
          style={{ background: 'linear-gradient(135deg, rgba(168,85,247,0.3), rgba(236,72,153,0.2), rgba(10,10,20,0))' }}>
          <div className="absolute inset-0 opacity-5" style={{ backgroundImage: 'radial-gradient(circle at 2px 2px, white 1px, transparent 0)', backgroundSize: '24px 24px' }} />
          <div className="relative">
            <p className="text-gray-400 text-sm font-medium mb-1">{greeting()}{user ? `, ${user.username}` : ''} 👋</p>
            <h1 className="text-3xl md:text-5xl font-black text-white mb-2">
              What's your vibe<br />
              <span className="gradient-text">today?</span>
            </h1>
            <p className="text-gray-500 text-sm mt-3">Discover new music, revisit favorites</p>
            {trending[0] && (
              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.97 }}
                onClick={() => playSong(trending[0], trending, 0)}
                className="mt-5 gradient-bg text-white font-semibold px-6 py-3 rounded-full flex items-center gap-2 shadow-xl shadow-purple-500/30"
              >
                <HiPlay /> Play Trending
              </motion.button>
            )}
          </div>
        </div>
      </motion.div>

      {/* Trending */}
      <Section title={<>🔥 Trending Now</>} loading={loading} count={5}>
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
          {trending.slice(0, 10).map((song, i) => (
            <SongCard key={song._id} song={song} queue={trending} queueIndex={i} />
          ))}
        </div>
      </Section>

      {/* Recently played */}
      {recentlyPlayed.length > 0 && (
        <Section title="🕐 Recently Played" loading={false}>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
            {recentlyPlayed.slice(0, 5).map((song, i) => (
              <SongCard key={song._id} song={song} queue={recentlyPlayed} queueIndex={i} />
            ))}
          </div>
        </Section>
      )}

      {/* Featured playlists */}
      <Section title="✨ Featured Playlists" loading={loading} count={5}>
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
          {playlists.slice(0, 10).map(pl => <PlaylistCard key={pl._id} playlist={pl} />)}
