        <h2 className="text-xl font-bold text-white mb-4">🎵 All Songs</h2>
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
          {songs.map((song, i) => (
            <SongCard key={song._id} song={song} queue={songs} queueIndex={i} />
