          </p>
        </div>
      </motion.div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';
import { songsAPI, artistsAPI, playlistsAPI } from '../services/api';
import { SongCard } from '../components/ui/SongCard';
import { ArtistCard } from '../components/ui/ArtistCard';
import { PlaylistCard } from '../components/ui/PlaylistCard';
import { SkeletonCard } from '../components/ui/Skeleton';
import { HiSearch, HiX } from 'react-icons/hi';

const TABS = ['All', 'Songs', 'Artists', 'Playlists'];

function useDebounce(value, delay) {
  const [debounced, setDebounced] = useState(value);
  useEffect(() => {
    const t = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(t);
  }, [value, delay]);
  return debounced;
}

export default function Search() {
  const [query, setQuery] = useState('');
  const [tab, setTab] = useState('All');
  const [results, setResults] = useState({ songs: [], artists: [], playlists: [] });
  const [loading, setLoading] = useState(false);
  const debouncedQuery = useDebounce(query, 350);
  const inputRef = useRef(null);

  useEffect(() => { inputRef.current?.focus(); }, []);

  useEffect(() => {
    if (!debouncedQuery.trim()) { setResults({ songs: [], artists: [], playlists: [] }); return; }
    setLoading(true);
    Promise.all([
      songsAPI.search(debouncedQuery),
      artistsAPI.search(debouncedQuery),
      playlistsAPI.getPublic(),
    ]).then(([s, a, p]) => {
      const pFiltered = (p.data.playlists || []).filter(pl =>
        pl.name.toLowerCase().includes(debouncedQuery.toLowerCase())
      );
      setResults({ songs: s.data.songs || [], artists: a.data.artists || [], playlists: pFiltered });
    }).catch(() => {}).finally(() => setLoading(false));
  }, [debouncedQuery]);

  const showSongs = tab === 'All' || tab === 'Songs';
  const showArtists = tab === 'All' || tab === 'Artists';
  const showPlaylists = tab === 'All' || tab === 'Playlists';
  const hasResults = results.songs.length || results.artists.length || results.playlists.length;

  return (
    <div className="p-6 md:p-8">
      <h1 className="text-3xl font-black text-white mb-6">Search</h1>

      {/* Search bar */}
      <div className="relative mb-6">
        <HiSearch className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 text-xl" />
        <input
          ref={inputRef}
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Search songs, artists, playlists..."
          className="w-full max-w-2xl bg-white/6 border border-white/10 rounded-2xl pl-12 pr-12 py-4 text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/60 transition-all text-base"
          style={{ background: 'rgba(255,255,255,0.05)' }}
        />
        {query && (
          <button
            onClick={() => setQuery('')}
            className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-600 hover:text-white transition-colors"
          >
            <HiX />
          </button>
        )}
      </div>

      {/* Filter tabs */}
      {query && (
        <div className="flex gap-2 mb-6">
          {TABS.map(t => (
            <motion.button
              key={t}
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => setTab(t)}
              className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all ${tab === t ? 'gradient-bg text-white shadow-lg' : 'glass text-gray-400 hover:text-white'}`}
            >
              {t}
            </motion.button>
          ))}
        </div>
      )}

      {/* Loading */}
      {loading && (
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
          {Array.from({ length: 10 }).map((_, i) => <SkeletonCard key={i} />)}
        </div>
      )}

      {/* No results / empty state */}
      {!loading && query && !hasResults && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="text-center py-20"
        >
          <div className="text-6xl mb-4">🎵</div>
          <p className="text-white font-semibold text-xl mb-2">No results found</p>
          <p className="text-gray-500 text-sm">Try a different search term</p>
        </motion.div>
      )}

      {/* No query state */}
      {!query && (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-center py-20">
          <div className="text-6xl mb-4">🔍</div>
          <p className="text-white font-semibold text-xl mb-2">Search for anything</p>
          <p className="text-gray-500 text-sm">Find your favorite songs, artists, and playlists</p>
        </motion.div>
      )}

      {/* Results */}
      {!loading && hasResults && (
        <div className="space-y-10">
          {showSongs && results.songs.length > 0 && (
            <div>
              <h2 className="text-lg font-bold text-white mb-4">Songs ({results.songs.length})</h2>
              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                {results.songs.map((song, i) => (
                  <SongCard key={song._id} song={song} queue={results.songs} queueIndex={i} />
                ))}
              </div>
            </div>
          )}
          {showArtists && results.artists.length > 0 && (
            <div>
              <h2 className="text-lg font-bold text-white mb-4">Artists ({results.artists.length})</h2>
              <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 lg:grid-cols-6 gap-4">
                {results.artists.map(a => <ArtistCard key={a._id} artist={a} />)}
              </div>
            </div>
          )}
          {showPlaylists && results.playlists.length > 0 && (
            <div>
              <h2 className="text-lg font-bold text-white mb-4">Playlists ({results.playlists.length})</h2>
              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                {results.playlists.map(pl => <PlaylistCard key={pl._id} playlist={pl} />)}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { songsAPI } from '../services/api';
import { usePlayer } from '../context/PlayerContext';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { SkeletonBanner } from '../components/ui/Skeleton';
import { HiPlay, HiPause, HiHeart, HiMusicNote } from 'react-icons/hi';

function formatTime(s) {
  if (!s || isNaN(s)) return '0:00';
  return `${Math.floor(s / 60)}:${Math.floor(s % 60).toString().padStart(2, '0')}`;
}

export default function SongPage() {
  const { id } = useParams();
  const [song, setSong] = useState(null);
  const [liked, setLiked] = useState(false);
  const [loading, setLoading] = useState(true);
  const { playSong, currentSong, isPlaying, togglePlay } = usePlayer();
  const { user } = useAuth();
  const { toast } = useToast();
  const isCurrentSong = currentSong?._id === id;

  useEffect(() => {
    songsAPI.getById(id)
      .then(({ data }) => {
        setSong(data.song);
        setLiked(user?.likedSongs?.includes(data.song._id));
      })
      .catch(() => toast.error('Failed to load song'))
      .finally(() => setLoading(false));
  }, [id]);

  const handlePlay = () => {
    if (isCurrentSong) togglePlay();
    else if (song) playSong(song, [song], 0);
  };

  const handleLike = async () => {
    if (!user) { toast.info('Login to like songs'); return; }
    try {
      await songsAPI.like(song._id);
      setLiked(!liked);
      toast.success(liked ? 'Removed from liked songs' : 'Added to liked songs ❤️');
    } catch { toast.error('Failed to update like'); }
  };

  if (loading) return (
    <div className="p-6 space-y-6">
      <SkeletonBanner />
      <div className="space-y-3">{Array.from({length:4}).map((_,i) => <div key={i} className="skeleton h-4 rounded w-2/3" />)}</div>
    </div>
  );

  if (!song) return (
    <div className="p-6 text-center py-20">
      <p className="text-2xl mb-2">🎵</p>
      <p className="text-gray-400">Song not found</p>
    </div>
  );

  return (
    <div className="p-6 md:p-8 max-w-4xl mx-auto">
      {/* Hero */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex flex-col md:flex-row items-center md:items-end gap-8 mb-10"
      >
        <div className="relative flex-shrink-0">
          <motion.img
            src={song.coverImage}
            alt={song.title}
            className="w-56 h-56 rounded-3xl object-cover shadow-2xl shadow-purple-500/20"
            animate={isCurrentSong && isPlaying ? { rotate: [0, 360] } : {}}
            transition={{ duration: 12, repeat: Infinity, ease: 'linear' }}
          />
          {isCurrentSong && isPlaying && (
            <div className="absolute -inset-2 rounded-3xl border-2 border-purple-500/40 animate-pulse" />
          )}
        </div>

        <div className="flex-1 text-center md:text-left">
          <p className="text-xs text-gray-500 uppercase tracking-widest mb-2 font-medium">Single</p>
          <h1 className="text-4xl md:text-5xl font-black text-white mb-3">{song.title}</h1>
          <Link to={`/artist/${song.artist?._id}`}
            className="text-lg text-gray-400 hover:text-purple-400 transition-colors font-medium">
            {song.artist?.name || 'Unknown Artist'}
          </Link>
          <div className="flex items-center gap-3 text-sm text-gray-600 mt-2 justify-center md:justify-start">
            {song.album !== 'Single' && <span>{song.album}</span>}
            <span>·</span>
            <span>{formatTime(song.duration)}</span>
            <span>·</span>
            <span>{(song.plays || 0).toLocaleString()} plays</span>
          </div>

          {/* Controls */}
          <div className="flex items-center gap-4 mt-6 justify-center md:justify-start">
            <motion.button
              whileHover={{ scale: 1.08 }}
              whileTap={{ scale: 0.94 }}
              onClick={handlePlay}
              className="w-14 h-14 rounded-full gradient-bg flex items-center justify-center shadow-xl shadow-purple-500/30"
            >
              {isCurrentSong && isPlaying
                ? <HiPause className="text-white text-2xl" />
                : <HiPlay className="text-white text-2xl ml-0.5" />}
            </motion.button>
            <motion.button
              whileHover={{ scale: 1.1 }}
              onClick={handleLike}
              className={`w-11 h-11 rounded-full flex items-center justify-center text-2xl transition-all ${liked ? 'text-pink-500 bg-pink-500/15' : 'text-gray-600 bg-white/5 hover:text-pink-400 hover:bg-pink-500/10'}`}
            >
              <HiHeart className={liked ? 'fill-current' : ''} />
            </motion.button>
            {song.genre && (
              <span className="px-3 py-1.5 text-xs rounded-full glass text-purple-400 border border-purple-500/20">
                {song.genre}
              </span>
            )}
          </div>
        </div>
      </motion.div>

      {/* Lyrics */}
      {song.lyrics && (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
          className="glass rounded-3xl p-8"
        >
          <h2 className="text-lg font-bold text-white mb-5 flex items-center gap-2">
            <HiMusicNote className="text-purple-400" /> Lyrics
          </h2>
          <pre className="text-gray-300 text-sm leading-relaxed whitespace-pre-wrap font-sans">{song.lyrics}</pre>
        </motion.div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { songsAPI, artistsAPI } from '../services/api';
import { useToast } from '../context/ToastContext';
import { HiUpload, HiMusicalNote, HiPhotograph } from 'react-icons/hi';

export default function Upload() {
  const [artists, setArtists] = useState([]);
  const [form, setForm] = useState({
    title: '', artistId: '', album: '', genre: '', lyrics: '',
    audio: null, cover: null,
  });
  const [previews, setPreviews] = useState({ audio: null, cover: null });
  const [loading, setLoading] = useState(false);
  const [newArtistMode, setNewArtistMode] = useState(false);
  const [newArtist, setNewArtist] = useState({ name: '', bio: '', genre: '' });
  const { toast } = useToast();

  useEffect(() => {
    artistsAPI.getAll().then(({ data }) => setArtists(data.artists || [])).catch(() => {});
  }, []);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleFile = (e, field) => {
    const file = e.target.files[0];
    if (!file) return;
    setForm({ ...form, [field]: file });
    setPreviews(prev => ({ ...prev, [field]: URL.createObjectURL(file) }));
  };

  const handleCreateArtist = async () => {
    if (!newArtist.name.trim()) { toast.error('Artist name required'); return; }
    try {
      const fd = new FormData();
      fd.append('name', newArtist.name);
      fd.append('bio', newArtist.bio);
      fd.append('genre', newArtist.genre);
      const { data } = await artistsAPI.create(fd);
      setArtists(prev => [...prev, data.artist]);
      setForm(prev => ({ ...prev, artistId: data.artist._id }));
      setNewArtistMode(false);
      toast.success(`Artist "${data.artist.name}" created!`);
    } catch { toast.error('Failed to create artist'); }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.audio || !form.cover || !form.artistId) {
      toast.error('Audio file, cover image, and artist are required'); return;
    }
    setLoading(true);
    try {
      const fd = new FormData();
      fd.append('title', form.title);
      fd.append('artistId', form.artistId);
      fd.append('album', form.album);
      fd.append('genre', form.genre);
      fd.append('lyrics', form.lyrics);
      fd.append('audio', form.audio);
      fd.append('cover', form.cover);
      await songsAPI.upload(fd);
      toast.success('Song uploaded successfully! 🎵');
      setForm({ title: '', artistId: '', album: '', genre: '', lyrics: '', audio: null, cover: null });
      setPreviews({ audio: null, cover: null });
    } catch (err) {
      toast.error(err.response?.data?.message || 'Upload failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-6 md:p-8 max-w-2xl mx-auto">
      <div className="flex items-center gap-3 mb-8">
        <HiUpload className="text-purple-400 text-2xl" />
        <h1 className="text-2xl font-black text-white">Upload Song</h1>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Cover image */}
        <div>
          <label className="text-xs font-medium text-gray-400 uppercase tracking-wider block mb-2">Cover Image *</label>
          <label className="cursor-pointer block">
            <div className={`relative w-40 h-40 rounded-2xl border-2 border-dashed flex items-center justify-center overflow-hidden transition-all
              ${previews.cover ? 'border-purple-500/40' : 'border-white/10 hover:border-purple-500/30'}`}>
              {previews.cover
                ? <img src={previews.cover} alt="cover" className="w-full h-full object-cover" />
                : <div className="text-center p-4">
                    <HiPhotograph className="text-3xl text-gray-600 mx-auto mb-1" />
                    <p className="text-xs text-gray-600">Click to upload</p>
                  </div>}
            </div>
            <input type="file" accept="image/*" onChange={e => handleFile(e, 'cover')} className="hidden" />
          </label>
        </div>

        {/* Audio file */}
        <div>
          <label className="text-xs font-medium text-gray-400 uppercase tracking-wider block mb-2">Audio File *</label>
          <label className={`cursor-pointer block glass rounded-xl px-5 py-4 border border-dashed transition-all
            ${previews.audio ? 'border-purple-500/40 bg-purple-500/5' : 'border-white/10 hover:border-purple-500/30'}`}>
            <div className="flex items-center gap-3">
              <HiMusicalNote className={`text-xl ${previews.audio ? 'text-purple-400' : 'text-gray-600'}`} />
              <span className={`text-sm ${previews.audio ? 'text-purple-400' : 'text-gray-500'}`}>
                {form.audio ? form.audio.name : 'Click to select audio file (MP3, WAV, OGG)'}
              </span>
            </div>
            <input type="file" accept="audio/*" onChange={e => handleFile(e, 'audio')} className="hidden" />
          </label>
        </div>

        {/* Artist */}
        <div>
          <div className="flex items-center justify-between mb-2">
            <label className="text-xs font-medium text-gray-400 uppercase tracking-wider">Artist *</label>
            <button type="button" onClick={() => setNewArtistMode(!newArtistMode)}
              className="text-xs text-purple-400 hover:text-purple-300 transition-colors">
              {newArtistMode ? 'Select existing' : '+ New artist'}
            </button>
          </div>
          {newArtistMode
            ? <div className="glass rounded-xl p-4 space-y-3">
                <input name="name" placeholder="Artist name" value={newArtist.name}
                  onChange={e => setNewArtist({...newArtist, name: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-white text-sm focus:outline-none focus:border-purple-500/60" />
                <input name="genre" placeholder="Genre" value={newArtist.genre}
                  onChange={e => setNewArtist({...newArtist, genre: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-white text-sm focus:outline-none focus:border-purple-500/60" />
                <textarea placeholder="Bio (optional)" value={newArtist.bio}
                  onChange={e => setNewArtist({...newArtist, bio: e.target.value})}
                  rows={2}
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-white text-sm focus:outline-none focus:border-purple-500/60 resize-none" />
                <button type="button" onClick={handleCreateArtist}
                  className="gradient-bg text-white px-4 py-2 rounded-lg text-sm font-medium">Create Artist</button>
              </div>
            : <select name="artistId" value={form.artistId} onChange={handleChange} required
                className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-purple-500/60 text-sm">
                <option value="">Select an artist</option>
                {artists.map(a => <option key={a._id} value={a._id}>{a.name}</option>)}
              </select>}
        </div>

        {/* Metadata */}
        {[
          { name: 'title', label: 'Song Title *', placeholder: 'Enter song title' },
          { name: 'album', label: 'Album', placeholder: 'Album name (optional)' },
          { name: 'genre', label: 'Genre', placeholder: 'e.g. Pop, Hip-Hop, R&B' },
        ].map(({ name, label, placeholder }) => (
          <div key={name}>
            <label className="text-xs font-medium text-gray-400 uppercase tracking-wider block mb-2">{label}</label>
            <input name={name} value={form[name]} onChange={handleChange}
              placeholder={placeholder} required={name === 'title'}
              className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/60 transition-all text-sm" />
          </div>
        ))}

        {/* Lyrics */}
        <div>
          <label className="text-xs font-medium text-gray-400 uppercase tracking-wider block mb-2">Lyrics</label>
          <textarea name="lyrics" value={form.lyrics} onChange={handleChange}
            placeholder="Paste lyrics here..." rows={8}
            className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/60 transition-all text-sm resize-none" />
        </div>

        <motion.button
          type="submit"
          disabled={loading}
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.98 }}
          className="w-full gradient-bg text-white font-bold py-4 rounded-xl flex items-center justify-center gap-2 shadow-xl shadow-purple-500/20 disabled:opacity-50 text-base"
        >
          {loading
            ? <><div className="w-5 h-5 border-2 border-white/40 border-t-white rounded-full animate-spin" /> Uploading to Cloudinary...</>
            : <><HiUpload className="text-xl" /> Upload Song</>}
        </motion.button>
      </form>
    </div>
  );
}
